insert into knowledge_nodes (id, project_id, node_key, label, category, sub_label, facts, talkpoint, description, sort_order) values
  ('131c6712-5f6a-5d36-a5fc-d2e8321c369e','00000000-0000-0000-0000-00000000b002','tgc','The Global City','project','Đại đô thị 117,4 ha — downtown mới khu Đông','[{"key":"Tên thương mại","value":"The Global City (tiền thân: KĐT Sài Gòn Bình An)"},{"key":"Vị trí","value":"Đỗ Xuân Hợp, P. Bình Trưng (trước là P. An Phú, Q.2 / TP. Thủ Đức), TP.HCM"},{"key":"Quy mô","value":"117,4 ha · mật độ xây dựng ~28%"},{"key":"Chủ đầu tư pháp lý","value":"CTCP Đầu tư và Phát triển Sài Gòn (SDI Corp)"},{"key":"Nhà phát triển","value":"Masterise Homes"},{"key":"Quy hoạch tổng thể","value":"Foster + Partners (Anh) · cảnh quan WATG (Mỹ)"},{"key":"Khởi công","value":"Tháng 3/2021"},{"key":"Sản phẩm","value":"~1.800–2.392 thấp tầng + ~8.000–10.000 căn hộ cao tầng"}]'::jsonb,'Câu chuyện đầu tư trong 3 dòng: quỹ đất sạch 117 ha cuối cùng tại lõi khu Đông, được quy hoạch bởi hãng kiến trúc làm Apple Park, định vị "downtown mới" của TP.HCM — với tiện ích đã hiện hữu (kênh nhạc nước 2 km, SOHO vận hành, sổ hồng đã trao) và "điểm rơi" hạ tầng 2026–2028.','Định danh dự án Tên thương mại The Global City (tiền thân: KĐT Sài Gòn Bình An) Vị trí Đỗ Xuân Hợp, P. Bình Trưng (trước là P. An Phú, Q.2 / TP. Thủ Đức), TP.HCM Quy mô 117,4 ha · mật độ xây dựng ~28% Chủ đầu tư pháp lý CTCP Đầu tư và Phát triển Sài Gòn (SDI Corp) Nhà phát triển Masterise Homes Quy hoạch tổng thể Foster + Partners (Anh) · cảnh quan WATG (Mỹ) Khởi công Tháng 3/2021 Sản phẩm ~1.800–2.392 thấp tầng + ~8',0),
  ('3b52c8df-c022-511b-abb2-962aabe8008f','00000000-0000-0000-0000-00000000b002','tq-vitri','Vị trí 3 mặt tiền','masterplan','Đỗ Xuân Hợp · Liên Phường 60m · song hành cao tốc','[]'::jsonb,'The Global City sở hữu 3 mặt tiền : đường Đỗ Xuân Hợp (lộ giới ~30m), đường Liên Phường (lộ giới 60m chạy xuyên dự án — Masterise chi hơn 350 tỷ hoàn thiện, thông xe kỹ thuật 8/11/2025) và đường song hành cao tốc TP.HCM – Long Thành – Dầu Giây.','Tọa độ chiến lược The Global City sở hữu 3 mặt tiền : đường Đỗ Xuân Hợp (lộ giới ~30m), đường Liên Phường (lộ giới 60m chạy xuyên dự án — Masterise chi hơn 350 tỷ hoàn thiện, thông xe kỹ thuật 8/11/2025) và đường song hành cao tốc TP.HCM – Long Thành – Dầu Giây. Dự án giáp sông Rạch Chiếc , cách Thảo Điền ~5 phút, Thủ Thiêm ~7–10 phút, lõi Quận 1 ~15–20 phút (tùy giờ). Vì sao vị trí này "đắt" Nằm giữa 2 cực giá trị:',1),
  ('734deb7f-cb0c-559e-b38a-d1f88c4ef54b','00000000-0000-0000-0000-00000000b002','tq-quymo','Quy mô 117,4 ha','masterplan','Mật độ xây dựng ~28% · ~25% xanh & mặt nước','[{"key":"Tổng diện tích","value":"1.174.221,9 m² (≈117,4 ha)"},{"key":"Mật độ xây dựng","value":"~28% — thấp so với mặt bằng nội đô"},{"key":"Công viên","value":"~13 ha cảnh quan"},{"key":"Xanh + mặt nước","value":"Quảng bá tới ~450.000 m² (~25–26% diện tích)"},{"key":"Tổng thầu","value":"Tung Feng · An Phong · Central"}]'::jsonb,'Mật độ thấp + quỹ xanh lớn là luận điểm bán hàng then chốt khi so với các dự án cao tầng thuần túy cùng tầm giá.','Tổng diện tích 1.174.221,9 m² (≈117,4 ha) Mật độ xây dựng ~28% — thấp so với mặt bằng nội đô Công viên ~13 ha cảnh quan Xanh + mặt nước Quảng bá tới ~450.000 m² (~25–26% diện tích) Tổng thầu Tung Feng · An Phong · Central Dự án thuộc cụm đô thị Rạch Chiếc ~500 ha cùng Saigon Sports City (Keppel) và khu liên hợp TDTT Rạch Chiếc — tạo "critical mass" cho cả vùng giá trị.',2),
  ('2ddd36b3-2e10-5cba-8650-e4baad043319','00000000-0000-0000-0000-00000000b002','tq-foster','Foster + Partners','masterplan','Hãng kiến trúc làm Apple Park · The Gherkin','[]'::jsonb,'Giá trị với nhà đầu tư: thương hiệu thiết kế quốc tế là "mã gen" khó sao chép, hỗ trợ định giá premium và khả năng giữ giá thứ cấp.','Foster + Partners (Anh Quốc) của huyền thoại Norman Foster làm quy hoạch tổng thể & kiến trúc — lần đầu tiên hãng nhận quy hoạch tổng thể một dự án tại Việt Nam. Track record toàn cầu Apple Park (trụ sở Apple, Mỹ) The Gherkin & trụ sở Bloomberg (London) Hearst Tower (New York) Sân bay quốc tế Bắc Kinh Cảnh quan bởi WATG (Mỹ); kết hợp Quimera Energy Efficiency cho giải pháp bền vững.',3),
  ('0733bcca-385d-5986-a6a1-df614e1678db','00000000-0000-0000-0000-00000000b002','tq-dinhvi','Định vị "Downtown mới"','masterplan','City within a city · all-in-one','[]'::jsonb,'"Downtown mới" là khẩu hiệu marketing của CĐT — khi tư vấn nên dẫn kèm bằng chứng hiện hữu (nhạc nước, SOHO, City Park đã vận hành) thay vì chỉ nói khẩu hiệu.','Masterise định vị The Global City là "trung tâm mới" / "downtown thứ hai" của TP.HCM theo mô hình city-within-a-city : ở – làm việc – mua sắm – học hành – y tế – giải trí trong một đô thị, tiếp nối lõi Nguyễn Huệ – Lê Lợi và bổ trợ Thủ Thiêm. Trụ cột định vị Thương mại: TTTM 123.000 m² + phố SOHO + Diners Square Giáo dục: 6 trường chuẩn quốc tế (điểm nhấn King''s College Wimbledon) Y tế: quỹ đất bệnh viện quốc tế ~2 h',4),
  ('93cd8f24-6aee-5a72-aa09-5623acca4bb5','00000000-0000-0000-0000-00000000b002','tq-sanpham','Cơ cấu sản phẩm','masterplan','Thấp tầng + cao tầng + thương mại','[]'::jsonb,'Tổng thể: ~1.800–2.392 sản phẩm thấp tầng và ~8.000–10.000 căn hộ cao tầng (số liệu dao động giữa các nguồn — quy hoạch điều chỉnh theo thời gian).','Dòng sản phẩm Quy mô Trạng thái Nhà phố thương mại SOHO 915 căn Đã bàn giao, đã trao sổ Nhà phố vườn Diners Square ~487 căn Theo quy hoạch Biệt thự SOLA (Đảo Ánh Dương) ~426 căn* Đang bán Dinh thự Oasis ~22 căn Theo quy hoạch Căn hộ Masteri Grand View 616 căn Cất nóc ~01/2026 Căn hộ Lumière Midtown 808 căn Bàn giao dự kiến T8/2027 Căn hộ Masteri Park Place (CT5) 4 tháp + VP Mở bán 10/2025 Căn hộ Masteri Cosmo Central',5),
  ('9c9ff5db-69ff-585c-84d5-4eec9ee29e92','00000000-0000-0000-0000-00000000b002','tq-rachchiec','Cụm đô thị Rạch Chiếc','masterplan','~500 ha cùng Saigon Sports City','[]'::jsonb,'The Global City nằm trong cụm đô thị Rạch Chiếc gần 500 ha — quy hoạch gồm:','The Global City nằm trong cụm đô thị Rạch Chiếc gần 500 ha — quy hoạch gồm: Saigon Sports City (Keppel Land): khu phức hợp thể thao – đô thị Khu liên hợp TDTT Rạch Chiếc : quy hoạch trung tâm thể thao thành phố The Global City : trung tâm thương mại – tài chính – cư trú Hiệu ứng cụm: nhiều CĐT lớn cùng đầu tư hạ tầng – tiện ích vào một vùng làm tăng tốc độ "lên đời" của cả khu vực, thay vì một dự án đơn độc tự gánh.',6),
  ('7cbc2f8c-0973-5662-a19f-68c04d337c73','00000000-0000-0000-0000-00000000b002','cdt-masterise','Masterise Homes','developer','Nhà phát triển BĐS hàng hiệu lớn nhất ĐNÁ','[]'::jsonb,'Masterise Homes (thuộc Masterise Group, tiền thân CTCP Đầu tư Thảo Điền 2007, đổi tên 2019) là nhà phát triển branded residences lớn nhất Đông Nam Á , hợp tác Marriott International, Elie Saab, Foster + Partners.','Masterise Homes (thuộc Masterise Group, tiền thân CTCP Đầu tư Thảo Điền 2007, đổi tên 2019) là nhà phát triển branded residences lớn nhất Đông Nam Á , hợp tác Marriott International, Elie Saab, Foster + Partners. Vai trò tại The Global City Masterise Homes là nhà phát triển (developer); chủ đầu tư pháp lý trên giấy tờ là SDI Corp . Phân biệt này quan trọng khi đọc HĐMB và đánh giá rủi ro pháp nhân. Năng lực bàn giao',7),
  ('6a37622d-d8c9-5126-a78f-e537622796f0','00000000-0000-0000-0000-00000000b002','cdt-group','Masterise Group','developer','Vốn 35.227 tỷ · lấn sân hàng không','[]'::jsonb,'Ý nghĩa với nhà đầu tư: tập đoàn mẹ quy mô lớn và đang mở rộng — tín hiệu về năng lực huy động vốn, song cũng đồng nghĩa nguồn lực bị phân bổ cho nhiều "mặt trận".','Theo VnExpress, Masterise Group đã tăng vốn lên hơn 35.227 tỷ đồng và mở rộng sang mảng hàng không với dự án Cảng hàng không quốc tế Gia Bình (Bắc Ninh), tổng mức đầu tư dự kiến hơn 196.000 tỷ đồng . Ông Hồ Anh Minh (SN 1995, con trai Chủ tịch Techcombank Hồ Hùng Anh) được bổ nhiệm Tổng Giám đốc Masterise Group ngày 13/1/2025.',8),
  ('d89852c2-7f50-5ed7-afc0-7c229caec4e6','00000000-0000-0000-0000-00000000b002','cdt-tcb','Hệ sinh thái Techcombank','developer','Gia đình Chủ tịch Hồ Hùng Anh sở hữu >10%','[]'::jsonb,'Góc nhìn 2 chiều: (+) trục ngân hàng – CĐT giúp chính sách vay 70–80%, HTLS 0% vận hành trơn tru; (–) mức độ tập trung rủi ro vào một hệ sinh thái — yếu tố cần cân nhắc ở vị thế danh mục lớn.','Masterise Group có liên hệ mật thiết với Techcombank : theo báo cáo quản trị Techcombank 2025, các thành viên gia đình Chủ tịch Hồ Hùng Anh (vợ Nguyễn Thị Thanh Thủy, con Hồ Anh Minh, Hồ Thủy Anh, em Hồ Anh Ngọc) đều sở hữu trên 10% vốn Masterise Group . Ông Hồ Anh Ngọc đồng thời là Phó Chủ tịch Techcombank. Techcombank/TCBS thường là bên thu xếp vốn, bảo lãnh, cho vay người mua tại các dự án Masterise. Ông Hồ Hùng A',9),
  ('b34710ed-7290-529f-afe0-dd5da23cac79','00000000-0000-0000-0000-00000000b002','cdt-sdi','SDI Corp','developer','Chủ đầu tư pháp lý · sức khỏe tài chính 2022','[{"key":"Lỗ sau thuế 2022","value":"hơn 3.096 tỷ đồng (gấp 20,3 lần 2021)"},{"key":"ROE","value":"âm 413,5%"},{"key":"Vốn chủ sở hữu","value":"còn gần 749 tỷ"},{"key":"Nợ phải trả","value":"96.385 tỷ — \"gấp 128 lần vốn chủ\""},{"key":"Dư nợ trái phiếu","value":"6.573 tỷ"}]'::jsonb,'CTCP Đầu tư và Phát triển Sài Gòn (SDI Corp) là pháp nhân được giao đất từ 2001 và đứng tên chủ đầu tư. Tháng 8/2021, SDI đổi đăng ký kinh doanh, dự án về tay nhóm Masterise và đổi tên thương mại thành The Global City.','CTCP Đầu tư và Phát triển Sài Gòn (SDI Corp) là pháp nhân được giao đất từ 2001 và đứng tên chủ đầu tư. Tháng 8/2021, SDI đổi đăng ký kinh doanh, dự án về tay nhóm Masterise và đổi tên thương mại thành The Global City. Cảnh báo tài chính (công bố HNX, nhadautu.vn 4/2023) Lỗ sau thuế 2022 hơn 3.096 tỷ đồng (gấp 20,3 lần 2021) ROE âm 413,5% Vốn chủ sở hữu còn gần 749 tỷ Nợ phải trả 96.385 tỷ — "gấp 128 lần vốn chủ" Dư',10),
  ('4d6cf4fa-b415-5341-866d-ce61824436e0','00000000-0000-0000-0000-00000000b002','cdt-track','Track record & Branded Residences','developer','Marriott · Elie Saab · minh chứng tăng giá','[]'::jsonb,'Lưu ý trung thực: hiệu suất quá khứ không bảo đảm tương lai; mặt bằng giá vào hiện đã cao hơn chu kỳ trước rất nhiều.','Danh mục Masterise là bằng chứng tăng giá hữu ích khi tư vấn: Masteri Thảo Điền (bàn giao 2016–2018): thứ cấp hiện ~100 triệu/m² — tăng nhiều lần so giá mở bán ~27–35 triệu/m². Grand Marina Saigon : branded residences Marriott/JW Marriott đầu tiên VN, thiết lập mặt bằng giá hạng sang Quận 1. The Rivus (Elie Saab): dòng dinh thự hàng hiệu thời trang đầu tiên châu Á. Logic bán hàng: chuỗi dự án "Masteri" có lịch sử bàn',11),
  ('0e9c3c63-42bd-518a-8340-80dd210fe250','00000000-0000-0000-0000-00000000b002','pl-timeline','Mốc pháp lý 1999–2017','policy','Từ sân golf Sài Gòn Bình An → khu đô thị','[]'::jsonb,'Điểm mạnh cốt lõi: đất đã được giao từ 2001, quy hoạch 1/500 phê duyệt 2015 — nền pháp lý gốc lâu đời và đầy đủ hiếm có ở quỹ đất trung tâm khu Đông.','Thời điểm Văn bản / Sự kiện 01/1999 UBND TP.HCM chấp thuận chủ trương đầu tư (~120 ha, ban đầu Cty Thiên Hải & liên doanh) 2000 Bổ sung sân golf An Phú, nâng quy mô ~137,44 ha 12/01/2001 QĐ 57/QĐ-TTg thu hồi & giao đất cho SDI Corp — dự án "Saigon Golf, Country Club and Residences" 2014–2015 TP.HCM đưa sân golf ra khỏi quy hoạch, chuyển hướng khu đô thị 30/11/2015 QĐ 6292/QĐ-UBND phê duyệt quy hoạch 1/500, diện tích',12),
  ('18a39f57-4552-56be-a80c-97fc474af104','00000000-0000-0000-0000-00000000b002','pl-gpxd','GPXD & đủ điều kiện bán','policy','155/GPXD 2020 · CV 7742 ngày 28/6/2022','[{"key":"GPXD hạ tầng","value":"Số 155/GPXD — Sở Xây dựng TP.HCM cấp 18/12/2020"},{"key":"Đủ ĐK bán hàng","value":"Công văn 7742/SXD-PTN&TTBĐS ngày 28/06/2022 (nhà ở hình thành trong tương lai)"},{"key":"Nghĩa vụ tài chính","value":"CĐT công bố đã hoàn thành nghĩa vụ tiền sử dụng đất"}]'::jsonb,null,'GPXD hạ tầng Số 155/GPXD — Sở Xây dựng TP.HCM cấp 18/12/2020 Đủ ĐK bán hàng Công văn 7742/SXD-PTN&TTBĐS ngày 28/06/2022 (nhà ở hình thành trong tương lai) Nghĩa vụ tài chính CĐT công bố đã hoàn thành nghĩa vụ tiền sử dụng đất Nguyên tắc thẩm định: văn bản đủ điều kiện bán hàng cấp theo từng phân khu/tháp . Trước khi cọc bất kỳ tháp mới nào (MPP, Cosmo Central…), yêu cầu CĐT/đại lý cung cấp công văn đủ điều kiện bán đ',13),
  ('e4381f0c-f18e-573e-bfb9-485f14e6628e','00000000-0000-0000-0000-00000000b002','pl-sohong','Sổ hồng SOHO 30/11/2024','policy','Bằng chứng "ra sổ" đầu tiên của đại đô thị','[]'::jsonb,'Script tư vấn: "Anh/chị không cần tin lời em — phân khu SOHO đã có cư dân nhận sổ hồng từ cuối 2024, em gửi hình ảnh & tin báo chí lễ trao sổ."','Masterise đã tổ chức trao sổ hồng nhà phố SOHO từ 30/11/2024 — chưa đầy 1 năm sau bàn giao nhà (hoàn thành xây dựng 2/2024). Vì sao đây là node quan trọng nhất khi tư vấn pháp lý Là bằng chứng thực tế dự án "ra sổ được" — mạnh hơn mọi cam kết trên giấy. Xác lập tiền lệ quy trình: bàn giao → hoàn công → cấp sổ trong ~12 tháng ở phân khu đầu. Trả lời trực diện nỗi sợ lớn nhất của khách Việt sau giai đoạn 2022–2023: "mu',14),
  ('4181383e-c491-5881-a183-a527708e09bb','00000000-0000-0000-0000-00000000b002','pl-sohuu','Hình thức sở hữu','policy','Lâu dài (người Việt) · 50 năm (nước ngoài)','[{"key":"Người Việt Nam","value":"Sở hữu lâu dài (đất ở đô thị)"},{"key":"Người nước ngoài","value":"50 năm theo luật hiện hành, có thể gia hạn"},{"key":"Pháp lý đất","value":"Các khu thấp tầng, cao tầng, thương mại có GCN QSDĐ riêng (theo CĐT)"}]'::jsonb,'Sở hữu lâu dài là lợi thế so với một số dự án căn hộ có thời hạn 50 năm trên thị trường — ảnh hưởng trực tiếp đến giá trị chuyển nhượng dài hạn và tâm lý người mua để ở.','Người Việt Nam Sở hữu lâu dài (đất ở đô thị) Người nước ngoài 50 năm theo luật hiện hành, có thể gia hạn Pháp lý đất Các khu thấp tầng, cao tầng, thương mại có GCN QSDĐ riêng (theo CĐT) Sở hữu lâu dài là lợi thế so với một số dự án căn hộ có thời hạn 50 năm trên thị trường — ảnh hưởng trực tiếp đến giá trị chuyển nhượng dài hạn và tâm lý người mua để ở.',15),
  ('46c113e6-f546-52a4-944f-3a8ba3d47a88','00000000-0000-0000-0000-00000000b002','pl-nganhang','Ngân hàng tài trợ & bảo lãnh','policy','Techcombank chủ đạo · BIDV (Cosmo)','[]'::jsonb,'Khi ký HĐMB, kiểm tra: (1) chứng thư bảo lãnh nghĩa vụ tài chính của CĐT cho đúng căn mình mua; (2) căn đã được giải chấp khỏi khoản vay dự án của CĐT trước khi ký.','Techcombank/TCBS : bên thu xếp vốn chủ đạo của hệ sinh thái Masterise; ngân hàng cho vay người mua tại nhiều phân khu. BIDV : hỗ trợ vay tối đa 70% tại Masteri Cosmo Central. Masteri Park Place : vay 70% qua ngân hàng đối tác, HTLS 0% đến 31/10/2028.',16),
  ('a8148863-4615-55b6-8813-cec44b3450bb','00000000-0000-0000-0000-00000000b002','pl-luuy','Hồ sơ rủi ro lịch sử','policy','Thanh tra · trái phiếu · tranh chấp bán hàng','[]'::jsonb,'Dự án từng bị chỉ ra các tồn tại: ký quỹ chậm, thẩm quyền phê duyệt ĐTM, xác định tiền sử dụng đất, khu tái định cư 10 ha. Đây là vấn đề lịch sử cần theo dõi xử lý dứt điểm.','1 · Tồn tại từ Thanh tra Chính phủ (giai đoạn SDI/Sài Gòn Bình An) Dự án từng bị chỉ ra các tồn tại: ký quỹ chậm, thẩm quyền phê duyệt ĐTM, xác định tiền sử dụng đất, khu tái định cư 10 ha. Đây là vấn đề lịch sử cần theo dõi xử lý dứt điểm. 2 · Khối trái phiếu gắn dự án (2021–2022) Đợt phát hành Giá trị Osaka Garden, Hoàng Phú Vương, Hoa Phú Thịnh (7–10/2021) 15.500 tỷ SDI Corp — lô SDICB2124001 (15/12/2021, 36 tháng',17),
  ('4feecd63-5853-53ed-9cc4-b3b2495c1f7b','00000000-0000-0000-0000-00000000b002','pl-checklist','Checklist thẩm định trước cọc','policy','7 bước due diligence cho người mua','[]'::jsonb,'Khoản đầu tư 6–20+ tỷ xứng đáng 5–10 triệu phí luật sư rà HĐMB độc lập.','1. Công văn đủ điều kiện bán hàng đúng tháp/phân khu định mua (không dùng công văn phân khu khác). 2. Văn bản xác nhận căn đã giải chấp / không thế chấp tại ngân hàng (rút kinh nghiệm vụ LK6). 3. Chứng thư bảo lãnh ngân hàng cho nghĩa vụ bàn giao của CĐT, ghi đúng mã căn. 4. Đối chiếu tiến độ thanh toán với trần luật: ≤70% trước bàn giao (CĐT trong nước), ≤95% trước khi cấp sổ. 5. Điều khoản phạt chậm bàn giao / chậm',18),
  ('60c38133-e6fb-525e-8099-dc6bc927009c','00000000-0000-0000-0000-00000000b002','pk-soho','SOHO','cluster','915 nhà phố thương mại · đã bàn giao + sổ','[{"key":"Quy mô","value":"915 căn · 15 dãy LK1–LK15"},{"key":"Diện tích đất","value":"95–141 m² · 1 trệt + 4 lầu, có thang máy"},{"key":"Bàn giao","value":"Hoàn thiện ngoài + thô trong · xong 2/2024"},{"key":"Sổ hồng","value":"Trao từ 30/11/2024"},{"key":"Giá thị trường","value":"~36–72 tỷ/căn (căn góc lớn tới ~100 tỷ)"},{"key":"Đơn giá đất","value":"~315–548 triệu/m² (CĐT công bố ~350–400)"}]'::jsonb,'Phù hợp: khách khai thác kinh doanh/cho thuê thương mại, đặc biệt căn đối diện Lotte Mall & mặt tiền Liên Phường. Tín hiệu vào tiền tốt: lấp đầy nội khu vượt ~60% + Lotte Mall chốt ngày khai trương.','Quy mô 915 căn · 15 dãy LK1–LK15 Diện tích đất 95–141 m² · 1 trệt + 4 lầu, có thang máy Bàn giao Hoàn thiện ngoài + thô trong · xong 2/2024 Sổ hồng Trao từ 30/11/2024 Giá thị trường ~36–72 tỷ/căn (căn góc lớn tới ~100 tỷ) Đơn giá đất ~315–548 triệu/m² (CĐT công bố ~350–400) Vận hành thương mại Đã có Katinat, Phúc Long, Pizza 4P''s, Highlands, Trung Nguyên, San Fu Lou, Kings Cross, Wall Street English, Kinder Academy…',19),
  ('0b98cbb2-9611-507d-b55f-0e416273a278','00000000-0000-0000-0000-00000000b002','pk-sola','SOLA — Đảo Ánh Dương','cluster','Biệt thự bán đảo 3 mặt sông · 47–200 tỷ/căn','[{"key":"Quy mô","value":"~426 căn (có nguồn 369) · ~9,86–12,3 ha"},{"key":"Đặc điểm","value":"Bán đảo 3 mặt giáp sông Rạch Chiếc + kênh đào · ~70.000 m² mặt nước"},{"key":"Loại hình","value":"Liên kế, boutique shop, song lập, đơn lập, dinh thự"},{"key":"Giá","value":"~47–200 tỷ/căn · ~400–450 triệu/m² đất · song lập từ ~56,9 tỷ, đơn lập từ ~80 tỷ"},{"key":"Thiết kế","value":"Foster + Partners"},{"key":"Chính sách","value":"Vay 70% · HTLS đến 30/6/2027 · ân hạn gốc đến 30/6/2028"}]'::jsonb,'Phân khúc siêu sang: thanh khoản hẹp, người mua là giới chủ giữ tài sản dài hạn. Luận điểm: khan hiếm tuyệt đối — biệt thự đảo giữa downtown mới, không thể tái tạo quỹ đất tương tự.','Quy mô ~426 căn (có nguồn 369) · ~9,86–12,3 ha Đặc điểm Bán đảo 3 mặt giáp sông Rạch Chiếc + kênh đào · ~70.000 m² mặt nước Loại hình Liên kế, boutique shop, song lập, đơn lập, dinh thự Giá ~47–200 tỷ/căn · ~400–450 triệu/m² đất · song lập từ ~56,9 tỷ, đơn lập từ ~80 tỷ Thiết kế Foster + Partners Chính sách Vay 70% · HTLS đến 30/6/2027 · ân hạn gốc đến 30/6/2028',20),
  ('5d93d070-4f22-50b7-b7f7-94fcd178233b','00000000-0000-0000-0000-00000000b002','pk-mgv','Masteri Grand View','cluster','616 căn · cất nóc 01/2026 · bàn giao 2026','[{"key":"Quy mô GĐ1","value":"2 tháp Spark & Glow · 25 tầng · 616 căn (308/tháp) · 8 căn/sàn"},{"key":"Loại căn","value":"1PN 56,6–61 m² → 4PN 136–181 m² · Penthouse 143–372 m²"},{"key":"Mở bán","value":"2/11/2024 · giá ~100 triệu/m² (sau CK, chưa VAT)"},{"key":"Chính sách lúc mở","value":"CK tới 16% thanh toán sớm · vay 80% LS 0%"},{"key":"Tiến độ","value":"Cất nóc ~29–30/1/2026 · bàn giao dự kiến 2026"},{"key":"Thứ cấp niêm yết","value":"~106,6–216,1 triệu/m² (Batdongsan, T2/2026 — giá rao)"}]'::jsonb,'MGV là "phép thử" cao tầng đầu tiên: nếu bàn giao đúng hạn 2026 và ra sổ suôn sẻ, toàn bộ mặt bằng giá các tháp sau (MPP, Cosmo) được hưởng lợi niềm tin. Giá rao thứ cấp ≠ giá khớp — cần đối chiếu giao dịch thực.','Quy mô GĐ1 2 tháp Spark & Glow · 25 tầng · 616 căn (308/tháp) · 8 căn/sàn Loại căn 1PN 56,6–61 m² → 4PN 136–181 m² · Penthouse 143–372 m² Mở bán 2/11/2024 · giá ~100 triệu/m² (sau CK, chưa VAT) Chính sách lúc mở CK tới 16% thanh toán sớm · vay 80% LS 0% Tiến độ Cất nóc ~29–30/1/2026 · bàn giao dự kiến 2026 Thứ cấp niêm yết ~106,6–216,1 triệu/m² (Batdongsan, T2/2026 — giá rao)',21),
  ('60cfd8a4-e749-5966-8874-25ef347b741e','00000000-0000-0000-0000-00000000b002','pk-lumiere','Lumière Midtown','cluster','808 căn · đối diện TTTM · bàn giao T8/2027','[{"key":"Quy mô","value":"2 tháp 23 tầng · 808 căn"},{"key":"Vị trí","value":"Mặt tiền Liên Phường, đối diện TTTM 123.000 m²"},{"key":"Bàn giao","value":"Dự kiến T8/2027"}]'::jsonb,'Dòng Lumière là thương hiệu cận cao cấp – cao cấp của Masterise. Vị trí đối diện Lotte Mall cho lợi thế khai thác cho thuê khi TTTM vận hành — nhưng cũng chịu mật độ thương mại/giao thông cao hơn các tháp ven kênh.','Quy mô 2 tháp 23 tầng · 808 căn Vị trí Mặt tiền Liên Phường, đối diện TTTM 123.000 m² Bàn giao Dự kiến T8/2027 Dòng Lumière là thương hiệu cận cao cấp – cao cấp của Masterise. Vị trí đối diện Lotte Mall cho lợi thế khai thác cho thuê khi TTTM vận hành — nhưng cũng chịu mật độ thương mại/giao thông cao hơn các tháp ven kênh.',22),
  ('df3409b9-dce2-5cdd-92b8-cacf3552365b','00000000-0000-0000-0000-00000000b002','pk-mpp','Masteri Park Place (CT5)','cluster','4 tháp + tháp văn phòng · trái tim kênh nhạc nước','[{"key":"Quy mô","value":"3,12 ha · 4 tháp căn hộ (A1, A2: 24 tầng · B1, B2: 27 tầng) + 1 tháp văn phòng ~30 tầng · 3 tầng đế · 2 hầm liên thông"},{"key":"Ra mắt","value":"Kick-off 15/10/2025 · nhà mẫu 22/11/2025"},{"key":"Sản phẩm","value":"1PN–4PN, Penthouse, Duplex, shophouse"},{"key":"Diện tích (tim tường)","value":"1PN 51,9–56 · 2PN 76,8–81 · 3PN 98,4–110 · 4PN 128,5–135,3 m²"},{"key":"Giá tham khảo","value":"~110,3–144,7 triệu/m² (view sông/nhạc nước ~125–145)"},{"key":"Giá theo căn","value":"1PN ~6,1–7,3 tỷ · 2PN ~8,5–10,3 tỷ · 4PN từ ~19,7 tỷ"},{"key":"Tiến độ","value":"Khởi công tháp đầu Q2/2026 · cất nóc dự kiến Q4/2027 · bàn giao dự kiến Q1/2028"},{"key":"HĐMB","value":"Ký dự kiến T5/2026"}]'::jsonb,'Đây là phân khu chủ lực để tư vấn nhà đầu tư trung hạn 2025–2026: vị trí lõi cạnh kênh nhạc nước + chính sách đòn bẩy mạnh nhất hệ thống (xem node Chính sách MPP & Dòng tiền MPP).','Quy mô 3,12 ha · 4 tháp căn hộ (A1, A2: 24 tầng · B1, B2: 27 tầng) + 1 tháp văn phòng ~30 tầng · 3 tầng đế · 2 hầm liên thông Ra mắt Kick-off 15/10/2025 · nhà mẫu 22/11/2025 Sản phẩm 1PN–4PN, Penthouse, Duplex, shophouse Diện tích (tim tường) 1PN 51,9–56 · 2PN 76,8–81 · 3PN 98,4–110 · 4PN 128,5–135,3 m² Giá tham khảo ~110,3–144,7 triệu/m² (view sông/nhạc nước ~125–145) Giá theo căn 1PN ~6,1–7,3 tỷ · 2PN ~8,5–10,3 tỷ',23),
  ('c7d0d4f1-6ad5-5939-928d-14ed4a518a98','00000000-0000-0000-0000-00000000b002','pk-cosmo','Masteri Cosmo Central (CT4)','cluster','6 tháp · 4 mặt tiền · ra mắt 15/1/2026','[{"key":"Quy mô","value":"6 tháp 19–29 tầng · 3 tầng đế · 2 hầm (CT3+CT4 thông nhau) · cụm CT4 ra trước với 3 tòa A, B1, B2"},{"key":"Vị trí","value":"4 mặt tiền: kênh nhạc nước – Liên Phường 60m – D3 30m – phố SOHO"},{"key":"Thiết kế","value":"Ngôn ngữ \"Terra Tropical\""},{"key":"Sản phẩm","value":"1PN–4PN, Duplex, Penthouse, căn thương mại"},{"key":"Tiến độ 1/2026","value":"Khoan cọc, thi công hầm"}]'::jsonb,'So với MPP: Cosmo có HTLS dài hơn ~5 tháng và CK sâu hơn, đổi lại vị trí sát phố SOHO (sầm uất hơn, ồn hơn) thay vì lõi ven kênh. Phù hợp khách ưu tiên dòng chính sách.','Quy mô 6 tháp 19–29 tầng · 3 tầng đế · 2 hầm (CT3+CT4 thông nhau) · cụm CT4 ra trước với 3 tòa A, B1, B2 Vị trí 4 mặt tiền: kênh nhạc nước – Liên Phường 60m – D3 30m – phố SOHO Thiết kế Ngôn ngữ "Terra Tropical" Sản phẩm 1PN–4PN, Duplex, Penthouse, căn thương mại Tiến độ 1/2026 Khoan cọc, thi công hầm Chính sách: CK sớm 2% · BIDV vay 70% · CK 7% (tiến độ) → ~14–14,5% (thanh toán sớm) · HTLS 0% đến 28/3/2029 · miễn ph',24),
  ('1dc99321-770e-55c7-9a77-c7d970109558','00000000-0000-0000-0000-00000000b002','pk-future','Quỹ tháp tương lai','cluster','The Peak · Midtown (chưa chính thức)','[]'::jsonb,'Một số nguồn thị trường nêu các cụm tương lai: The Peak (2 tháp 43 tầng, căn 3–4PN) và Midtown (3 tháp 38–40 tầng). Chưa có công bố chính thức từ CĐT — chỉ dùng làm tham chiếu về tổng nguồn cung tương lai của đại đô thị (~8.000–10.000 căn hộ).','Một số nguồn thị trường nêu các cụm tương lai: The Peak (2 tháp 43 tầng, căn 3–4PN) và Midtown (3 tháp 38–40 tầng). Chưa có công bố chính thức từ CĐT — chỉ dùng làm tham chiếu về tổng nguồn cung tương lai của đại đô thị (~8.000–10.000 căn hộ). Ý nghĩa đầu tư 2 chiều: nguồn cung tương lai lớn có thể pha loãng tăng giá ngắn hạn các tháp hiện hữu, nhưng cũng kéo dài "vòng đời marketing" và mật độ cư dân — tốt cho khai t',25),
  ('69eb4524-cc11-5a42-b2b6-697640039384','00000000-0000-0000-0000-00000000b002','cs-mpp','Chính sách MPP','finance','Early bird · 3 phương án · HTLS 0% đến 31/10/2028','[]'::jsonb,'24 tháng kể từ ngày CĐT gửi thông báo bàn giao căn hộ.','Ưu đãi Early Bird (đến hết 30/11/2025) Khách hàng thông thường: chiết khấu 1% Cư dân Masterise Homes: chiết khấu 2% (điều kiện xác định theo CSBH của CĐT) Hỗ trợ phí quản lý 24 tháng kể từ ngày CĐT gửi thông báo bàn giao căn hộ. 3 phương án thanh toán (dự kiến) Phương án Cấu trúc chính Ưu đãi Tiến độ chuẩn Đặt trước 100tr → XNĐK 10% → HĐMB (T5/2026) 10% → các đợt 5–10% mỗi 60–90 ngày → bàn giao 25% + KPBT → 5% khi sổ',26),
  ('d2dfef6c-8f3e-5ccf-bb63-8a7465f89a3b','00000000-0000-0000-0000-00000000b002','cs-cosmo','Chính sách Cosmo Central','finance','BIDV 70% · CK tới ~14,5% · HTLS đến 28/3/2029','[]'::jsonb,'So sánh nhanh trong hệ The Global City: Cosmo cho ưu đãi tài chính "dày" nhất hiện tại; MPP cho vị trí lõi ven kênh. Quyết định nên dựa trên mục tiêu (giữ lâu → vị trí; tối ưu vốn ngắn hạn → chính sách).','Chiết khấu booking sớm: 2% Vay BIDV tối đa 70% , HTLS 0% đến 28/3/2029 Chiết khấu: ~7% (tiến độ) → ~14–14,5% (thanh toán sớm) Miễn phí quản lý 24 tháng',27),
  ('1c476edf-486e-5fcb-bcca-c268b36c2ca2','00000000-0000-0000-0000-00000000b002','cs-mgv','Chính sách MGV (lúc mở bán)','finance','CK tới 16% · vay 80% LS 0%','[]'::jsonb,'Giá trị tham chiếu: cho thấy "khẩu vị" chính sách của Masterise qua từng giai đoạn — mở bán sâu CK, cận bàn giao siết lại. Nhà đầu tư vào sớm thường nhận cấu trúc ưu đãi tốt nhất, đổi lấy rủi ro tiến độ dài hơn.','Tại thời điểm mở bán 11/2024: chiết khấu thanh toán sớm tới 16% , vay tới 80% lãi suất 0%. Hiện giai đoạn này đã đóng; MGV chuyển sang giai đoạn cận bàn giao với chính sách khác.',28),
  ('f19bf255-c0c7-5c6b-9c54-1dee5fb938c7','00000000-0000-0000-0000-00000000b002','cs-sola','Chính sách SOLA','finance','Vay 70% · HTLS đến 30/6/2027','[]'::jsonb,'Với giá trị căn 47–200 tỷ, đòn bẩy 70% tạo nghĩa vụ nợ rất lớn sau ưu đãi — phân khúc này thường phù hợp vốn tự có cao, dùng vay ở tỷ trọng thấp như công cụ tối ưu thuế/dòng tiền.','Vay tối đa 70% giá trị Hỗ trợ lãi suất đến 30/6/2027 Ân hạn gốc đến 30/6/2028 Với giá trị căn 47–200 tỷ, đòn bẩy 70% tạo nghĩa vụ nợ rất lớn sau ưu đãi — phân khúc này thường phù hợp vốn tự có cao, dùng vay ở tỷ trọng thấp như công cụ tối ưu thuế/dòng tiền.',29),
  ('191204e8-4b82-5c00-9e32-9d5c43a48883','00000000-0000-0000-0000-00000000b002','ti-kenh','Kênh nhạc nước 2km','amenity','"The Canal of Love" · vận hành từ 9/2023','[]'::jsonb,'Kênh đào nhạc nước "The Canal of Love" dài 2 km , quảng bá "lớn nhất Đông Nam Á". Khai trương giai đoạn 1 (Fountain Festival) 1/9/2023 ; đã hoàn thiện toàn tuyến 2 km, vận hành các show lớn, đón khách miễn phí.','Kênh đào nhạc nước "The Canal of Love" dài 2 km , quảng bá "lớn nhất Đông Nam Á". Khai trương giai đoạn 1 (Fountain Festival) 1/9/2023 ; đã hoàn thiện toàn tuyến 2 km, vận hành các show lớn, đón khách miễn phí. Vai trò đầu tư Proof of concept : tiện ích "đinh" đã hiện hữu trước khi bán phần lớn căn hộ — ngược quy trình thông thường (bán trước, tiện ích sau). Máy tạo traffic : điểm check-in kéo khách toàn TP về dự án',30),
  ('36c19643-82e4-525a-bf70-f3372e399a76','00000000-0000-0000-0000-00000000b002','ti-citypark','City Park','amenity','Tổ hợp giải trí – thể thao · mở 30/3/2024','[]'::jsonb,'City Park — tổ hợp giải trí & thể thao (gồm đường đua Go-Kart) mở cửa 30/3/2024 . Cùng kênh nhạc nước, đây là tầng tiện ích "đời sống cuối tuần" giúp dự án có nhịp sống thật trước khi cư dân cao tầng dọn về — yếu tố các đại đô thị vùng ven thường thiếu trong 3–5 năm đầu.','City Park — tổ hợp giải trí & thể thao (gồm đường đua Go-Kart) mở cửa 30/3/2024 . Cùng kênh nhạc nước, đây là tầng tiện ích "đời sống cuối tuần" giúp dự án có nhịp sống thật trước khi cư dân cao tầng dọn về — yếu tố các đại đô thị vùng ven thường thiếu trong 3–5 năm đầu.',31),
  ('186bf6b4-db79-54f6-971d-34732f2ed98f','00000000-0000-0000-0000-00000000b002','ti-lotte','TTTM 123.000 m² (Lotte)','amenity','Dự kiến khai trương cuối 2026','[{"key":"Quy mô","value":"123.000 m² — quảng bá TTTM lớn nhất TP.HCM"},{"key":"Vị trí","value":"Trục Liên Phường, đối diện Lumière Midtown"},{"key":"Thương hiệu","value":"Lotte Mall Global City (theo nguồn CĐT/đại lý)"},{"key":"Tiến độ","value":"Hoàn thiện mặt ngoài (kính Low-E) · setup gian hàng từ Q3/2026 · khai trương dự kiến cuối 2026"}]'::jsonb,'Vì sao node này quan trọng: ngày khai trương TTTM là chất xúc tác giá mạnh nhất nội khu — kinh nghiệm các đại đô thị cho thấy giá thuê & giá bán quanh mall tăng rõ rệt 6–12 tháng quanh mốc khai trương.','Quy mô 123.000 m² — quảng bá TTTM lớn nhất TP.HCM Vị trí Trục Liên Phường, đối diện Lumière Midtown Thương hiệu Lotte Mall Global City (theo nguồn CĐT/đại lý) Tiến độ Hoàn thiện mặt ngoài (kính Low-E) · setup gian hàng từ Q3/2026 · khai trương dự kiến cuối 2026 Lưu ý xác minh: hợp tác Lotte do nguồn CĐT/đại lý (masterland.vn, bachnhuproperties.vn) công bố, chưa có thông cáo độc lập từ Lotte ; trước đây từng có thông',32),
  ('56c860b8-9b18-5d19-8847-f8de2b344c2a','00000000-0000-0000-0000-00000000b002','ti-kings','King''s College Wimbledon','amenity','Khai giảng 8/2027 · campus ~2 ha · 2–18 tuổi','[]'::jsonb,'King''s College School, Wimbledon HCMC (hợp tác Millennia Education) — lễ công bố 9/5/2026; khai giảng khóa đầu tháng 8/2027 ; campus gần 2 ha; nhận học sinh 2–18 tuổi; là cơ sở khu vực thứ hai sau Bangkok.','King''s College School, Wimbledon HCMC (hợp tác Millennia Education) — lễ công bố 9/5/2026; khai giảng khóa đầu tháng 8/2027 ; campus gần 2 ha; nhận học sinh 2–18 tuổi; là cơ sở khu vực thứ hai sau Bangkok. Hiệu trưởng sáng lập Kieran McLaughlin: quy mô kỳ vọng ~1.500 học sinh, năm đầu mở dần ~2 lớp/khối từ mầm non; cơ sở có hồ bơi trong nhà 25 m, nhà hát 500 chỗ; học phí "phân khúc cao cấp". Tác động giá trị Trường q',33),
  ('7d407300-c246-5baf-8cd0-5696a452f657','00000000-0000-0000-0000-00000000b002','ti-benhvien','Bệnh viện quốc tế','amenity','Quỹ đất ~2 ha · chưa công bố đơn vị vận hành','[]'::jsonb,'Quy hoạch bệnh viện tiêu chuẩn quốc tế trên quỹ đất ~2 ha / 20.000 m². Chưa công bố đơn vị vận hành ; một số nguồn nêu phương án CĐT xây và bàn giao cho UBND TP. Thủ Đức — chưa được xác minh độc lập.','Quy hoạch bệnh viện tiêu chuẩn quốc tế trên quỹ đất ~2 ha / 20.000 m². Chưa công bố đơn vị vận hành ; một số nguồn nêu phương án CĐT xây và bàn giao cho UBND TP. Thủ Đức — chưa được xác minh độc lập. Khi tư vấn: nói "quy hoạch có bệnh viện quốc tế" — không hứa thương hiệu/thời điểm vì chưa có thông tin chính thức.',34),
  ('b03da1f7-55ee-513c-a4cd-0a77f6c4effc','00000000-0000-0000-0000-00000000b002','ti-vanphong','Văn phòng & MICE','amenity','Tháp hạng A · Convention Center · Lifestyle Hub','[]'::jsonb,'Cụm tháp văn phòng hạng A (gồm 1 tháp ~30 tầng trong CT5/MPP), Business Center, Convention Center, Lifestyle Hub 5 sao.','Cụm tháp văn phòng hạng A (gồm 1 tháp ~30 tầng trong CT5/MPP), Business Center, Convention Center, Lifestyle Hub 5 sao. Ý nghĩa đầu tư: nguồn cầu thuê căn hộ bền nhất là người làm việc tại chỗ . Văn phòng hạng A vận hành = tệp khách thuê chuyên gia/quản lý ngay nội khu, giảm phụ thuộc tệp thuê từ Q.1/Thảo Điền.',35),
  ('45e4e908-ff22-5ed2-8c80-a1500e7b505a','00000000-0000-0000-0000-00000000b002','ti-mpp30','30+ tiện ích MPP','amenity','Masteri Collection · công viên ven sông','[]'::jsonb,'Phòng khách – bếp – ngủ bàn giao theo bộ chuẩn Masteri Collection (thiết bị thương hiệu, hoàn thiện cao cấp) — đồng nhất chuỗi Masteri, giảm chi phí hoàn thiện cho người mua đầu tư cho thuê.','Hệ tiện ích nội khu MPP Ngoài trời: công viên ven sông, bể bơi resort ngoài trời Trong nhà: gym, yoga, Teen Club, Kid Room, thư viện, sảnh đón chuẩn khách sạn Tiêu chuẩn bàn giao Masteri Collection Phòng khách – bếp – ngủ bàn giao theo bộ chuẩn Masteri Collection (thiết bị thương hiệu, hoàn thiện cao cấp) — đồng nhất chuỗi Masteri, giảm chi phí hoàn thiện cho người mua đầu tư cho thuê.',36),
  ('535a61bf-0539-507a-92a1-808a318a9cf0','00000000-0000-0000-0000-00000000b002','ht-anphu','Nút giao An Phú','infra','>3.400 tỷ · ~70% tiến độ · đích 30/6/2026','[]'::jsonb,'Đây là công trình tác động trực tiếp nhất đến trải nghiệm di chuyển vào The Global City từ trung tâm. Mốc 30/6/2026 nếu đạt sẽ là chất xúc tác tâm lý mạnh đúng giai đoạn ký HĐMB MPP (T5/2026).','Nút giao 3 tầng An Phú (tổng vốn >3.400 tỷ). Theo Giám đốc Ban Giao thông TP.HCM Nguyễn Anh Minh (3/2026): tổng tiến độ ~70% ; hầm chui HC1 thông xe 2/2/2026; cầu N2 hoàn thành cuối 2025; các nhánh N1.1/N1.3 đạt ~40%, dự kiến hoàn thành 30/6/2026 ; còn 64 hộ trên Lương Định Của chờ giải tỏa (~1.800 tỷ bồi thường).',37),
  ('31bb9585-87b7-576e-a655-50730bf7d9b9','00000000-0000-0000-0000-00000000b002','ht-vd3','Vành đai 3','infra','Thông xe kỹ thuật cuối 2025 · hoàn thành giữa 2026','[]'::jsonb,'Vành đai 3 TP.HCM (76,3 km): thông xe kỹ thuật ~14,7 km cuối 2025; mục tiêu thông xe 30/4/2026, hoàn thành 30/6/2026; nút giao Tân Vạn cơ bản hoàn thành cuối 2025.','Vành đai 3 TP.HCM (76,3 km): thông xe kỹ thuật ~14,7 km cuối 2025; mục tiêu thông xe 30/4/2026, hoàn thành 30/6/2026; nút giao Tân Vạn cơ bản hoàn thành cuối 2025. Tác động: tái phân bố logistics & dân cư về phía Đông, rút ngắn liên kết vùng (Bình Dương – Đồng Nai – Long An) — nền cho chu kỳ giá BĐS khu Đông giai đoạn 2026–2030.',38),
  ('4a6fb79f-8431-531a-a71e-b5acffdfdb3f','00000000-0000-0000-0000-00000000b002','ht-caotoc','Cao tốc Long Thành mở rộng','infra','Lên 8–10 làn · 2025–2027','[]'::jsonb,'Rủi ro thi công: giai đoạn mở rộng có thể gây ùn ứ cục bộ 2025–2027 trước khi thông thoáng — chuẩn bị tâm lý cho khách ở thật về trải nghiệm ngắn hạn.','Cao tốc TP.HCM – Long Thành – Dầu Giây đang mở rộng lên 8–10 làn (2025–2027) — giải nút thắt tuyến huyết mạch nối The Global City (qua đường song hành) với sân bay Long Thành.',39),
  ('16fe113a-43c2-5c78-bf79-0050180babf5','00000000-0000-0000-0000-00000000b002','ht-lienphuong','Đường Liên Phường 60m','infra','Masterise chi >350 tỷ · thông xe KT 8/11/2025','[]'::jsonb,'Trục Liên Phường lộ giới 60 m chạy xuyên dự án; Masterise chi hơn 350 tỷ hoàn thiện đoạn kết nối; thông xe kỹ thuật 8/11/2025 . Đây là "đại lộ mặt tiền" của Lotte Mall, Lumière Midtown và Cosmo Central — đồng thời mở hướng kết nối về Vành đai 3/khu công nghệ cao.','Trục Liên Phường lộ giới 60 m chạy xuyên dự án; Masterise chi hơn 350 tỷ hoàn thiện đoạn kết nối; thông xe kỹ thuật 8/11/2025 . Đây là "đại lộ mặt tiền" của Lotte Mall, Lumière Midtown và Cosmo Central — đồng thời mở hướng kết nối về Vành đai 3/khu công nghệ cao.',40),
  ('3bbcaaa3-18d0-5a61-9a7e-6206ee3471ad','00000000-0000-0000-0000-00000000b002','ht-metro','Metro số 1 & nối dài','infra','Đã vận hành thương mại · đề xuất nối Long Thành','[]'::jsonb,'Trung thực khi tư vấn: The Global City không nằm sát ga metro — lợi thế metro là gián tiếp (nâng mặt bằng khu Đông), không phải tiện ích cửa nhà.','Metro số 1 (Bến Thành – Suối Tiên) đã vận hành thương mại — ga gần nhất cách dự án vài km (kết nối bằng buýt/xe cá nhân). Đề xuất kéo dài tuyến tới sân bay Long Thành (~60.000 tỷ, nghiên cứu 2026–2030).',41),
  ('44b30224-7e49-5683-8b2f-77f6ed08496a','00000000-0000-0000-0000-00000000b002','ht-longthanh','Sân bay Long Thành','infra','Khai thác thương mại Q4/2026 · 25 triệu khách/năm GĐ1','[]'::jsonb,'Kết luận của Thủ tướng Phạm Minh Chính khi kiểm tra hiện trường (29/3/2026): hoàn thành xây dựng trong quý 3/2026 , sang quý 4/2026 khai thác thương mại . Chuyến bay kỹ thuật đầu tiên (Boeing 787-9, Vietnam Airlines) hạ cánh 15/12/2025. Giai đoạn 1: 25 triệu khách/năm , vốn gần 110.000 tỷ (toàn dự á','Kết luận của Thủ tướng Phạm Minh Chính khi kiểm tra hiện trường (29/3/2026): hoàn thành xây dựng trong quý 3/2026 , sang quý 4/2026 khai thác thương mại . Chuyến bay kỹ thuật đầu tiên (Boeing 787-9, Vietnam Airlines) hạ cánh 15/12/2025. Giai đoạn 1: 25 triệu khách/năm , vốn gần 110.000 tỷ (toàn dự án >336.000 tỷ ≈ >14 tỷ USD). The Global City hưởng lợi kép: nằm trên trục cao tốc đi sân bay + đón tệp chuyên gia/quản l',42),
  ('6b70145f-16d2-58c3-8032-bcfb80a059ef','00000000-0000-0000-0000-00000000b002','ht-tacdong','"Điểm rơi" hạ tầng 2026–2028','infra','Cửa sổ cộng hưởng các mốc hoàn thành','[]'::jsonb,'Luận điểm thời điểm: người mua MPP giai đoạn 2025–2026 đang vào trước cụm chất xúc tác trên; bàn giao Q1/2028 rơi đúng lúc hệ sinh thái vận hành đầy đủ — cấu trúc thời gian hiếm khi đẹp như vậy, với điều kiện các mốc không trượt dài .','Mốc Thời điểm kỳ vọng Nút giao An Phú hoàn thành 30/6/2026 Vành đai 3 thông xe / hoàn thành 30/4 – 30/6/2026 Sân bay Long Thành khai thác Q4/2026 Lotte Mall khai trương (dự kiến) Cuối 2026 King''s College khai giảng 8/2027 MPP bàn giao Q1/2028 Luận điểm thời điểm: người mua MPP giai đoạn 2025–2026 đang vào trước cụm chất xúc tác trên; bàn giao Q1/2028 rơi đúng lúc hệ sinh thái vận hành đầy đủ — cấu trúc thời gian hiếm',43),
  ('bfd9e09a-c302-5151-b333-df3f206a5521','00000000-0000-0000-0000-00000000b002','tt-hcm','Bối cảnh thị trường HCM','comparable','CBRE/Savills 2025 · cao cấp dẫn dắt','[]'::jsonb,'Kết luận khung: The Global City đang bán đúng vùng giá thị trường cao cấp , không phải ngoại lệ đắt — nhưng cả mặt bằng chung đã ở mức cao, biên an toàn mỏng hơn chu kỳ trước.','Giá sơ cấp căn hộ TP.HCM tăng ~8% so 2024 (Savills Q3/2025); thứ cấp tăng 5–20% tùy khu, khu Đông mạnh nhất (Thủ Thiêm/Nam Rạch Chiếc 18–27%/năm; Thảo Điền/An Phú 13–19%/năm — Dat Xanh Services). Phân khúc cao cấp/hạng sang dẫn dắt nguồn cung mới; nhóm cao cấp hấp thụ ~91%. CBRE (ông Võ Huỳnh Tuấn Kiệt): dự án cao cấp phổ biến 120–150 triệu/m² , một số lên 180–200; giá thuê chỉ 15–30 triệu/tháng nên tỷ suất cho thuê',44),
  ('d468acb0-b384-5609-b346-aae4d7562ef2','00000000-0000-0000-0000-00000000b002','tt-giagc','Lịch sử giá The Global City','comparable','SOHO → MGV → MPP: mặt bằng leo thang','[]'::jsonb,null,'Phân khu Giá mở bán Hiện tại / rao SOHO (2022) ~315–400 tr/m² đất 36–72 tỷ/căn · +~4,5%/12 tháng MGV (11/2024) ~100 tr/m² Rao 106,6–216,1 tr/m² (T2/2026) MPP (10/2025) ~110–145 tr/m² Đang bán sơ cấp Mặt bằng căn hộ TGC — ~120–170 tr/m² tùy phân khu Giá rao thứ cấp (đặc biệt mức trần 216 tr/m²) gồm căn view đẹp tầng cao và mang tính niêm yết — không phải giá khớp . Một số tin "nhà phố chạm 400 triệu/m²" mang tính tiêu',45),
  ('7f9cd58f-bf65-529a-ba69-efc40a0ca658','00000000-0000-0000-0000-00000000b002','tt-yield','Cảnh báo tỷ suất cho thuê ~2%','comparable','Savills: yield căn hộ HCM giảm mạnh','[]'::jsonb,'Bà Cao Thị Thanh Hương (Savills Việt Nam): dữ liệu Savills cho thấy tỷ suất lợi nhuận cho thuê căn hộ TP.HCM "chỉ khoảng 2%/năm" — giảm mạnh so 5–6% giai đoạn trước 2023, do giá bán tăng nhanh hơn giá thuê.','Bà Cao Thị Thanh Hương (Savills Việt Nam): dữ liệu Savills cho thấy tỷ suất lợi nhuận cho thuê căn hộ TP.HCM "chỉ khoảng 2%/năm" — giảm mạnh so 5–6% giai đoạn trước 2023, do giá bán tăng nhanh hơn giá thuê. Hệ quả cho The Global City Lợi nhuận kỳ vọng đến chủ yếu từ tăng giá vốn (capital gain) , không phải dòng tiền thuê. Yield ~2% không đủ trả lãi vay thả nổi ~8–9,5% — đòn bẩy 70% chỉ an toàn khi có nguồn trả nợ độc',46),
  ('a1d538ae-70f0-528c-b7fa-0625ae05807d','00000000-0000-0000-0000-00000000b002','tt-eaton','Eaton Park (Gamuda)','comparable','Đối thủ trực diện · ~115+ tr/m²','[{"key":"Chủ đầu tư","value":"Gamuda Land (Malaysia)"},{"key":"Vị trí","value":"Mặt tiền Mai Chí Thọ, kề Thủ Thiêm"},{"key":"Giá","value":"~115+ triệu/m² · 1PN ~7 tỷ"},{"key":"Yield kỳ vọng","value":"5–6% (số đại lý — thận trọng)"}]'::jsonb,'So với TGC: Eaton Park gần lõi Thủ Thiêm hơn, nhưng là dự án đơn lẻ trong khu dân cư hiện hữu — thiếu hệ tiện ích đại đô thị (mall, trường, kênh nhạc nước) tự chủ. TGC thắng ở "hệ sinh thái", Eaton thắng ở khoảng cách tới Thủ Thiêm.','Chủ đầu tư Gamuda Land (Malaysia) Vị trí Mặt tiền Mai Chí Thọ, kề Thủ Thiêm Giá ~115+ triệu/m² · 1PN ~7 tỷ Yield kỳ vọng 5–6% (số đại lý — thận trọng) So với TGC: Eaton Park gần lõi Thủ Thiêm hơn, nhưng là dự án đơn lẻ trong khu dân cư hiện hữu — thiếu hệ tiện ích đại đô thị (mall, trường, kênh nhạc nước) tự chủ. TGC thắng ở "hệ sinh thái", Eaton thắng ở khoảng cách tới Thủ Thiêm.',47),
  ('27fed5fd-a5db-5ccf-8dd9-661a96c04687','00000000-0000-0000-0000-00000000b002','tt-vgp','Vinhomes Grand Park','comparable','Đại đô thị Q9 · 45–65 tr/m² · khác phân khúc','[]'::jsonb,'Không phải đối thủ trực tiếp về giá — là điểm so sánh giá trị : VGP chứng minh mô hình đại đô thị tự vận hành làm tăng giá & giữ thanh khoản; TGC bán cùng câu chuyện ở phân khúc cao gấp đôi, gần trung tâm hơn hẳn. Khách ngân sách 3–5 tỷ → VGP; 6 tỷ+ và cần "địa chỉ" trung tâm mới → TGC.','Vinhomes Grand Park (Quận 9 cũ): 45–65 triệu/m², 2PN từ ~2,9–3,5 tỷ; yield ~4–5,5% nhờ giá vốn thấp; hệ sinh thái Vin (VinMec, VinSchool, VinBus, Mega Mall đã vận hành).',48),
  ('4a6c68cf-aef9-5440-ad2f-998ca24d377a','00000000-0000-0000-0000-00000000b002','tt-thuthiem','Cụm Thủ Thiêm','comparable','Metropole · Empire City · Zeit River','[]'::jsonb,'Thủ Thiêm là "trần giá" khu Đông (300–440 tr/m²). Khoảng cách giá TGC (110–170) ↔ Thủ Thiêm tạo dư địa kể chuyện : nếu tin vào mô hình downtown mở rộng, TGC là "Thủ Thiêm cách đây một nhịp định giá". Ngược lại, đó cũng là lời nhắc TGC chưa phải lõi CBD.','Dự án Giá tham khảo The Metropole (SonKim Land) GĐ mới ~10.000 USD/m² · 2PN tới 300–440 tr/m² Empire City (Keppel & cộng sự) 1PN từ ~6 tỷ · tháp 88 tầng Zeit River (GS E&C) 1PN ~9,3 tỷ Thủ Thiêm là "trần giá" khu Đông (300–440 tr/m²). Khoảng cách giá TGC (110–170) ↔ Thủ Thiêm tạo dư địa kể chuyện : nếu tin vào mô hình downtown mở rộng, TGC là "Thủ Thiêm cách đây một nhịp định giá". Ngược lại, đó cũng là lời nhắc TGC',49),
  ('9724c734-872f-50f5-ab99-9e052a94a671','00000000-0000-0000-0000-00000000b002','tt-benchmark','Benchmark Masteri Thảo Điền','comparable','Mở ~27–35 → nay ~100 tr/m² thứ cấp','[]'::jsonb,'Masteri Thảo Điền — dự án "khai quốc" chuỗi Masteri: mở bán ~27–35 triệu/m² (2014–2015), thứ cấp hiện ~100 triệu/m². Là case minh chứng mạnh nhất khi khách hỏi "Masteri có giữ giá không?".','Masteri Thảo Điền — dự án "khai quốc" chuỗi Masteri: mở bán ~27–35 triệu/m² (2014–2015), thứ cấp hiện ~100 triệu/m². Là case minh chứng mạnh nhất khi khách hỏi "Masteri có giữ giá không?". Dùng có trách nhiệm: mức tăng đó thuộc chu kỳ giá đất 2014–2024 đặc biệt + vị trí cạnh metro. Lặp lại biên độ ấy từ nền giá 120+ tr/m² là kỳ vọng phi thực tế; kịch bản hợp lý cho TGC là tăng theo nhịp hạ tầng + lạm phát + premium h',50),
  ('57063a5f-a416-5041-ab8b-421a08e3eb16','00000000-0000-0000-0000-00000000b002','tt-thanhkhoan','Thanh khoản thứ cấp','comparable','Căn hộ > nhà phố > biệt thự siêu sang','[]'::jsonb,'Nhà phố SOHO và căn hộ TGC đã có giao dịch chuyển nhượng. Quy luật thanh khoản nội khu:','Nhà phố SOHO và căn hộ TGC đã có giao dịch chuyển nhượng. Quy luật thanh khoản nội khu: Căn hộ 1–2PN (6–10 tỷ): tệp mua lớn nhất, thoát hàng nhanh nhất. Nhà phố SOHO (36–72 tỷ): tệp hẹp, phụ thuộc câu chuyện khai thác thương mại. SOLA (47–200 tỷ): siêu hẹp — tài sản giữ, không phải tài sản lướt. Hàm ý: nhà đầu tư cần thanh khoản nên ở dòng căn hộ diện tích vừa, vị trí view đặc trưng (kênh/sông) để khác biệt khi bán l',51),
  ('c7a4c987-1dc8-53dd-94da-124cff8700fd','00000000-0000-0000-0000-00000000b002','dt-thesis','Luận điểm đầu tư','finance','4 trụ cột của investment thesis','[]'::jsonb,'Thesis đứng vững khi: hạ tầng không trượt dài + CĐT giữ tiến độ + thị trường cao cấp không gãy thanh khoản. Theo dõi node "Tín hiệu Mua/Thận trọng".','1 · Vị trí khan hiếm Quỹ đất sạch 117 ha cuối cùng tại lõi khu Đông, kẹp giữa Thảo Điền – Thủ Thiêm, 3 mặt tiền trục lớn. 2 · Thương hiệu & thiết kế Foster + Partners + chuỗi Masteri có lịch sử bàn giao — yếu tố "branded" hỗ trợ premium và giữ giá. 3 · Đòn bẩy hạ tầng đúng nhịp Cụm chất xúc tác 2026–2028: An Phú, Vành đai 3, Long Thành, Lotte Mall, King''s College — trùng chu kỳ xây dựng – bàn giao MPP/Cosmo. 4 · Tiện',52),
  ('8e02c009-9406-5fe5-b034-8b96f953bcdb','00000000-0000-0000-0000-00000000b002','dt-dongtien','Dòng tiền MPP (mô phỏng)','finance','Vay 70% · gánh nặng ≈0 tới sau bàn giao','[]'::jsonb,'Ví dụ căn 2PN ~9 tỷ, phương án vay 70%:','Ví dụ căn 2PN ~9 tỷ, phương án vay 70%: Giai đoạn Người mua chi Ghi chú Booking → ký HĐMB (T5/2026) ~10–20% (~0,9–1,8 tỷ) Theo đợt XNĐK/HĐMB Xây dựng → bàn giao (Q1/2028) Phần còn lại của 30% vốn tự có NH giải ngân 70% · LS 0% đến 31/10/2028 Sau bàn giao → 31/10/2029 Chưa trả gốc Ân hạn gốc · bắt đầu chịu lãi thả nổi từ 11/2028 Từ 11/2029 Gốc + lãi đầy đủ ~8–9,5%/năm thị trường "Vách đá" dòng tiền: từ 11/2028 lãi thả',53),
  ('42658a18-48d3-5afd-8764-356c32d55806','00000000-0000-0000-0000-00000000b002','dt-ruiro','Bản đồ rủi ro','finance','Pháp lý · tiến độ · thanh khoản · lãi suất · cung','[]'::jsonb,null,'Rủi ro Nội dung Giảm thiểu Pháp nhân CĐT Vết trái phiếu/VTP · SDI lỗ 3.096 tỷ, nợ 96.385 tỷ (2022) · vụ LK6 + phạt 225tr Checklist 7 bước · luật sư rà HĐMB · không thanh toán vượt trần luật Tiến độ hạ tầng An Phú từng lùi hạn (~70%, đích 30/6/2026) Kịch bản cơ sở giả định trượt 6–12 tháng Lãi suất sau ưu đãi Thả nổi 8–9,5% từ 11/2028 (MPP) Trả bớt gốc · chốt kế hoạch thoát trước Yield thấp ~2%/năm (Savills) — không g',54),
  ('05cb3eb8-3fa2-5f97-8b1a-82739a67edad','00000000-0000-0000-0000-00000000b002','dt-khuyennghi','Chọn phân khu theo mục tiêu','finance','Khung khuyến nghị hành động','[]'::jsonb,'Nguyên tắc chung: trong đại đô thị nguồn cung lớn, căn "có câu chuyện riêng" (view nhạc nước, tầng đẹp, layout hiếm) là thứ bảo vệ giá khi thị trường chững.','Mục tiêu Phân khu Điều kiện kích hoạt Tăng giá vốn trung hạn 2–4 năm MPP (CT5) căn view kênh/sông Giá ≤130 tr/m² · giữ được gói HTLS đến 31/10/2028 + ân hạn 2029 Tối ưu chính sách/CK Cosmo Central (CT4) CK 14%+ · HTLS đến 28/3/2029 · chấp nhận vị trí sát SOHO Khai thác thương mại SOHO đối diện TTTM/Liên Phường Lấp đầy nội khu >60% · Lotte chốt ngày khai trương Giữ tài sản siêu sang SOLA đơn lập view sông Vốn tự có ca',55),
  ('6c2f530f-f0e5-50aa-90d4-58be2566ffee','00000000-0000-0000-0000-00000000b002','dt-trigger','Tín hiệu Mua / Thận trọng','finance','Benchmark cập nhật quyết định','[]'::jsonb,null,'Tín hiệu MUA mạnh hơn Nút giao An Phú thông xe toàn bộ ~30/6/2026 Vành đai 3 thông xe 30/4–30/6/2026 Lotte Mall công bố mốc khai trương chính thức MGV bàn giao đúng hạn 2026 & ra sổ suôn sẻ Tín hiệu THẬN TRỌNG Hạ tầng trượt >6 tháng so mốc công bố Giá thứ cấp đi ngang/giảm khi khu Đông bung hàng Diễn biến pháp lý mới liên quan SDI Corp / khối trái phiếu Chính sách HTLS bị rút ngắn ở các đợt mở bán sau',56),
  ('ed5f7c6d-11c0-5077-b373-483596374c0a','00000000-0000-0000-0000-00000000b002','dt-kh','Chân dung khách mua MPP','finance','"The Energized Strivers"','[]'::jsonb,'Ứng dụng tư vấn: chốt khách ở thật bằng trải nghiệm (bình minh, view kênh, trường cho con); chốt nhà đầu tư bằng chính tệp khách thuê tương lai là nhóm này — chuyên gia trẻ thu nhập cao làm việc tại văn phòng nội khu/Thủ Thiêm.','CĐT định vị khách MPP là "The Energized Strivers" — thế hệ trẻ thành đạt giai đoạn sung sức: bứt phá sự nghiệp + vun đắp tổ ấm; lịch trình dày, deadline nối deadline, gia đình đa thế hệ. Với họ, nhà là "trạm tiếp năng lượng đa chiều" : tái tạo thể chất (vận động, thiên nhiên), nuôi dưỡng tinh thần (ánh sáng, thiết kế, cảnh quan), khơi mở kết nối (gia đình – cộng đồng – công việc). 4 nguồn năng lượng: Khởi sinh (ven s',57);
